    def mark_confirmed(self, request, queryset):
        count = 0
        for deposit in queryset.filter(status='pending'):
            deposit.status = 'confirmed'
            deposit.confirmed_by = request.user
            deposit.confirmed_at = timezone.now()
            deposit.save()

            count += 1

