    fieldsets = (
        ('User & Request', {
            'fields': ('user', 'requested_tier', 'amount')
        }),
        ('✅ APPROVAL', {
            'fields': ('status', 'rejection_reason', 'processed_by', 'processed_at'),
            'description': '<strong style="color: green;">Change status to "Approved" to upgrade user account</strong>'
        }),
    )

